#!/usr/bin/env python3# -*- coding: utf-8 -*-import jsonimport osimport loggingimport mathimport refrom typing import Dict, List, Optional, Tuplelogger = logging.getLogger(__name__)CACHE_FILE = "data/zone_params_cache.json"class ZoneParamsCollector:    """    Класс для сбора параметров номенклатурных листов    топографических карт для Тверской и Смоленской областей    """        ZONES_BASE = {        '4': {            'epsg': 28404,            'name': 'Зона 4 (СК-42)',            'central_meridian': 21,            'zone_number': 4,            'offset_x': 6100000,            'offset_y': 5300000,            'dx': 805,            'dy': 45        },        '5': {            'epsg': 28405,            'name': 'Зона 5 (СК-42)',            'central_meridian': 27,            'zone_number': 5,            'offset_x': 6200000,            'offset_y': 5500000,            'dx': 807,            'dy': 83        },        '6': {            'epsg': 28406,            'name': 'Зона 6 (СК-42)',            'central_meridian': 33,            'zone_number': 6,            'offset_x': 6200000,            'offset_y': 6500000,            'dx': 802,            'dy': 34        },        '7': {            'epsg': 28407,            'name': 'Зона 7 (СК-42)',            'central_meridian': 39,            'zone_number': 7,            'offset_x': 6210000,            'offset_y': 6650000,            'dx': 801,            'dy': -13        },        '8': {            'epsg': 28408,            'name': 'Зона 8 (СК-42)',            'central_meridian': 45,            'zone_number': 8,            'offset_x': 6220000,            'offset_y': 6800000,            'dx': 800,            'dy': -25        },        '9': {            'epsg': 28409,            'name': 'Зона 9 (СК-42)',            'central_meridian': 51,            'zone_number': 9,            'offset_x': 6230000,            'offset_y': 6950000,            'dx': 799,            'dy': -35        }    }    # Номенклатурные листы для Тверской и Смоленской областей    MAP_SHEETS = {        # Тверская область (зона 6)        'O-36-141': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'O-36-142': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'O-36-143': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'O-36-144': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'O-36-145': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'N-36-17': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'N-36-18': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'N-36-19': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'N-36-20': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'N-36-21': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},                # Смоленская область (зона 5)        'N-35-9': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'N-35-10': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'N-35-11': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-21': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-22': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-23': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-24': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-25': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-26': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-27': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-28': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'}    }    # Границы регионов    REGION_BOUNDARIES = {        'tver': {            'name': 'Тверская область',            'lat_min': 55.5,            'lat_max': 58.5,            'lon_min': 30.0,            'lon_max': 38.0        },        'smolensk': {            'name': 'Смоленская область',            'lat_min': 53.5,            'lat_max': 56.0,            'lon_min': 30.0,            'lon_max': 35.0        },        'moscow': {            'name': 'Московская область',            'lat_min': 54.5,            'lat_max': 57.0,            'lon_min': 35.0,            'lon_max': 40.0        }    }    def __init__(self):        self.cache = self._load_cache()    def _load_cache(self) -> Dict:        if os.path.exists(CACHE_FILE):            try:                with open(CACHE_FILE, 'r', encoding='utf-8') as f:                    return json.load(f)            except Exception as e:                logger.error(f"Ошибка загрузки кэша: {e}")        return {}    def _save_cache(self):        os.makedirs(os.path.dirname(CACHE_FILE), exist_ok=True)        try:            with open(CACHE_FILE, 'w', encoding='utf-8') as f:                json.dump(self.cache, f, ensure_ascii=False, indent=2)            logger.info(f"Кэш сохранен: {CACHE_FILE}")        except Exception as e:            logger.error(f"Ошибка сохранения кэша: {e}")    def get_zone_params(self, zone_number: str) -> Optional[Dict]:        return self.ZONES_BASE.get(zone_number)    def get_sheet_params(self, sheet_name: str) -> Optional[Dict]:        return self.MAP_SHEETS.get(sheet_name.upper())    def is_zonal_coordinate(self, x: float, y: float) -> bool:        """        Определяет, являются ли координаты уже зональными (СК-42)        Зональные координаты: x > 5,000,000 и y > 5,000,000        """        if x > 5000000 and y > 5000000:            return True        return False    def is_short_coordinate(self, x: float, y: float) -> bool:        """        Проверяет, являются ли координаты короткими (последние 5 цифр)        Короткие координаты: x < 100,000 и y < 100,000        """        if x < 100000 and y < 100000:            return True        return False    def detect_zone_from_zonal_y(self, y: float) -> Optional[str]:        """        Определяет зону по значению Y в зональных координатах        Первая цифра Y указывает на номер зоны        """        y_int = int(y)        y_str = str(y_int)        if len(y_str) >= 7:            zone_digit = y_str[0]            if zone_digit in self.ZONES_BASE:                return zone_digit        return None    def detect_region(self, lat: float, lon: float) -> str:        """Определяет регион по географическим координатам"""        for region_key, bounds in self.REGION_BOUNDARIES.items():            if (bounds['lat_min'] <= lat <= bounds['lat_max'] and                bounds['lon_min'] <= lon <= bounds['lon_max']):                return region_key        return 'unknown'    def decimal_to_dms(self, deg: float, direction: str) -> str:        """Преобразует десятичные градусы в формат градусы/минуты/секунды"""        if deg < 0:            deg = -deg            direction = 'Ю' if direction == 'N' else 'З'        degrees = int(deg)        minutes_float = (deg - degrees) * 60        minutes = int(minutes_float)        seconds = (minutes_float - minutes) * 60        return f"{degrees}°{minutes:02d}'{seconds:.1f}\" {direction}"    def calculate_coordinates(self, x: float, y: float, zone_number: str = None, sheet_name: str = None) -> Dict:        """        Основной метод расчета координат        """        result = {            'x_input': x,            'y_input': y,            'zone_number': zone_number,            'sheet': sheet_name,            'input_type': 'unknown',            'success': False,            'errors': [],            'region': 'unknown'        }        # Определяем тип ввода        is_zonal = self.is_zonal_coordinate(x, y)        is_short = self.is_short_coordinate(x, y)                # ========== 1. ЗОНАЛЬНЫЕ КООРДИНАТЫ (уже СК-42) ==========        if is_zonal:            result['input_type'] = 'zonal_sk42'            logger.info(f"Обнаружены зональные координаты СК-42: x={x}, y={y}")                        # Определяем зону по Y            if not zone_number:                zone_number = self.detect_zone_from_zonal_y(y)                if zone_number:                    result['zone_number'] = zone_number                    logger.info(f"Определена зона по Y: {zone_number}")                        zone_params = self.get_zone_params(zone_number) if zone_number else None            if not zone_params:                result['errors'].append(f"Не удалось определить зону для координат")                return result                        # Зональные координаты уже являются СК-42, НЕ ДОБАВЛЯЕМ СМЕЩЕНИЯ!            x_sk42 = x            y_sk42 = y            result['x_sk42'] = x_sk42            result['y_sk42'] = y_sk42            result['zone'] = zone_params['name']            result['epsg'] = zone_params['epsg']            result['central_meridian'] = zone_params['central_meridian']                    # ========== 2. КОРОТКИЕ КООРДИНАТЫ С ЛИСТОМ ==========        elif is_short and sheet_name:            result['input_type'] = 'short_with_sheet'            logger.info(f"Обнаружены короткие координаты с листом: {sheet_name}, x={x}, y={y}")                        sheet = self.get_sheet_params(sheet_name)            if not sheet:                result['errors'].append(f"Лист карты {sheet_name} не найден")                return result                        zone_number = sheet['zone']            result['zone_number'] = zone_number                        x_full = sheet['offset_x'] + x            y_full = sheet['offset_y'] + y            result['x_full'] = x_full            result['y_full'] = y_full                        zone_params = self.get_zone_params(zone_number)            if not zone_params:                result['errors'].append(f"Зона {zone_number} не найдена")                return result                        x_sk42 = x_full + sheet.get('dx', zone_params.get('dx', 0))            y_sk42 = y_full + sheet.get('dy', zone_params.get('dy', 0))                        result['x_sk42'] = x_sk42            result['y_sk42'] = y_sk42            result['zone'] = zone_params['name']            result['epsg'] = zone_params['epsg']            result['central_meridian'] = zone_params['central_meridian']                    # ========== 3. ЛОКАЛЬНЫЕ КООРДИНАТЫ (от рамки карты) ==========        else:            result['input_type'] = 'local'            logger.info(f"Обнаружены локальные координаты: x={x}, y={y}")                        if not zone_number:                # Пробуем определить зону автоматически                for z_num, z_params in self.ZONES_BASE.items():                    test_x = z_params['offset_x'] + x                    test_y = z_params['offset_y'] + y                    test_lat = test_x / 111000                    test_lon = z_params['central_meridian'] + ((test_y - (int(z_num) * 1000000)) / 85000)                    if (55.5 <= test_lat <= 58.5 and 30 <= test_lon <= 38) or \                       (53.5 <= test_lat <= 56.0 and 30 <= test_lon <= 35):                        zone_number = z_num                        logger.info(f"Автоматически определена зона: {zone_number}")                        break                                if not zone_number:                    zone_number = '6'                    logger.info(f"Используем зону по умолчанию: 6")                        zone_params = self.get_zone_params(zone_number)            if not zone_params:                result['errors'].append(f"Зона {zone_number} не найдена")                return result                        x_full = zone_params['offset_x'] + x            y_full = zone_params['offset_y'] + y            result['x_full'] = x_full            result['y_full'] = y_full                        x_sk42 = x_full + zone_params['dx']            y_sk42 = y_full + zone_params['dy']            result['x_sk42'] = x_sk42            result['y_sk42'] = y_sk42            result['zone'] = zone_params['name']            result['epsg'] = zone_params['epsg']            result['central_meridian'] = zone_params['central_meridian']        # ========== ПЕРЕСЧЕТ В ГЕОГРАФИЧЕСКИЕ КООРДИНАТЫ ==========        zone_num = int(zone_number) if zone_number else 6        y_local = result['y_sk42'] - (zone_num * 1000000)                # 1° широты = 111,000 м        # 1° долготы на широте ~55° = 85,000 м        lat = result['x_sk42'] / 111000        lon = result['central_meridian'] + (y_local / 85000)                result['latitude'] = lat        result['longitude'] = lon                # Определяем регион        result['region'] = self.detect_region(lat, lon)                # Форматируем DMS        result['latitude_dms'] = self.decimal_to_dms(lat, 'N')        result['longitude_dms'] = self.decimal_to_dms(lon, 'E')                result['success'] = True                region_name = self.REGION_BOUNDARIES.get(result['region'], {}).get('name', 'Неизвестно')        logger.info(f"Координаты: {lat:.4f}, {lon:.4f} -> {region_name}")        return result    def detect_zone_by_coordinates(self, x: float, y: float, zone_hint: str = None, sheet_name: str = None) -> Optional[Dict]:        if zone_hint and zone_hint in self.ZONES_BASE:            return self.ZONES_BASE[zone_hint]        if sheet_name:            sheet = self.get_sheet_params(sheet_name)            if sheet:                return self.ZONES_BASE.get(sheet['zone'])        if self.is_zonal_coordinate(x, y):            zone_num = self.detect_zone_from_zonal_y(y)            if zone_num:                return self.ZONES_BASE.get(zone_num)        return self.ZONES_BASE.get('6')    def get_all_zones(self) -> List[str]:        return list(self.ZONES_BASE.keys())    def get_all_sheets(self) -> List[str]:        return list(self.MAP_SHEETS.keys())    def get_region_info(self, region_key: str) -> Optional[Dict]:        return self.REGION_BOUNDARIES.get(region_key)    def get_all_regions(self) -> List[str]:        return list(self.REGION_BOUNDARIES.keys())def get_zone_params(zone_number: str) -> Optional[Dict]:    collector = ZoneParamsCollector()    return collector.get_zone_params(zone_number)def get_sheet_params(sheet_name: str) -> Optional[Dict]:    collector = ZoneParamsCollector()    return collector.get_sheet_params(sheet_name)def detect_zone_by_coords(x: float, y: float, zone_hint: str = None, sheet_name: str = None) -> Optional[Dict]:    collector = ZoneParamsCollector()    return collector.detect_zone_by_coordinates(x, y, zone_hint, sheet_name)def calculate_coordinates(x: float, y: float, zone_number: str = None, sheet_name: str = None) -> Dict:    collector = ZoneParamsCollector()    return collector.calculate_coordinates(x, y, zone_number, sheet_name)def get_all_zones() -> List[str]:    collector = ZoneParamsCollector()    return collector.get_all_zones()def get_all_sheets() -> List[str]:    collector = ZoneParamsCollector()    return collector.get_all_sheets()def get_region_info(region_key: str) -> Optional[Dict]:    collector = ZoneParamsCollector()    return collector.get_region_info(region_key)def get_all_regions() -> List[str]:    collector = ZoneParamsCollector()    return collector.get_all_regions()